  if (ok) pass++; else fail++;
  if (!ok) {
    console.log(`  ${icon} ${label}: 期待=${expected.toFixed(5)}, 実際=${actual.toFixed(5)}, 差=${(actual - expected).toFixed(6)}`);
  } else {
    console.log(`  ${icon} ${label}: ${actual.toFixed(4)} (期待 ${expected.toFixed(4)})`);
  }
}

function checkEq(label, actual, expected) {
  const ok = actual === expected;
  const icon = ok ? '✅' : '❌';
  if (ok) pass++; else fail++;
  console.log(`  ${icon} ${label}: ${JSON.stringify(actual)} (期待 ${JSON.stringify(expected)})`);
}

function checkTrue(label, actual) {
  const ok = actual === true;
  if (ok) pass++; else fail++;
  console.log(`  ${ok ? '✅' : '❌'} ${label}: ${actual}`);
}

function checkFalse(label, actual) {
  const ok = actual === false;
  if (ok) pass++; else fail++;
  console.log(`  ${ok ? '✅' : '❌'} ${label}: ${actual}`);
}

function checkNull(label, actual) {
  const ok = actual === null;
  if (ok) pass++; else fail++;
  console.log(`  ${ok ? '✅' : '❌'} ${label}: ${actual}`);
}

function checkGt(label, actual, threshold) {
  const ok = actual > threshold;
  if (ok) pass++; else fail++;
  console.log(`  ${ok ? '✅' : '❌'} ${label}: ${actual.toFixed(3)} (> ${threshold})`);
}

function checkLt(label, actual, threshold) {
  const ok = actual < threshold;
  if (ok) pass++; else fail++;
  console.log(`  ${ok ? '✅' : '❌'} ${label}: ${actual.toFixed(3)} (< ${threshold})`);
}

function checkNoError(r) {
  const ok = r.error === null;
  if (ok) pass++; else fail++;
  if (!ok) console.log(`  ❌ エラーあり: ${r.error}`);
}

function checkError(label, r) {
