//   Db  = (24.0 + 17.5) / 2 = 20.75
//   K   = 2.0/(2π×16) + 0.577×0.15×14.701/16 + 0.15×20.75/(2×16)
//       = 0.019894 + 0.079527 + 0.097266 = 0.196687
//   At  = 2.0/(2π) + 0.577×0.15×14.701 = 0.318310 + 1.272431 = 1.590741
//   dAs = √(4×157/π) = 14.136
//   Fy_denom = 1 + 3×(3/14.136 × 1.590741)² = 1 + 3×0.113966 = 1.341898
//   Fy  = 1100×157 / √1.341898 / 1000 = 172700 / 1.158404 / 1000 ≈ 149.0 kN
//   T_lim = 0.196687 × 16 × 149.0 ≈ 468.8 N·m
console.log('\n【TC-04】 M16 / 12.9 / s45c / dry（大径高強度ボルト）');
{
  const r = Bolt.calc({ d: 16, grade: '12.9', partMat: 's45c', mu: 'dry' });
  checkNull('error = null', r.error);
  check('K', r.K, 0.19669, 1e-4);
  check('Fy kN', r.Fy, 149.0, 0.5);
  check('T_lim N·m', r.T_lim, 468.8, 1.0);
  checkFalse('isMaterialLimit = false（S45C は軟質材外）', r.isMaterialLimit);
  checkGt('T_lim > 400 N·m（大径高強度）', r.T_lim, 400);
  checkEq('dominant = 座面陥没', r.dominant, '座面陥没');
  check('T_jis = T_lim/1.5', r.T_jis, r.T_lim / 1.5, 0.01);
}

// ─── TC-05: M12 / A4-80 / resin / dry（ステンレスボルト・最軟質材）──
// 手計算根拠:
//   BOLT_DATA[12]: p=1.75, d2=10.863, As=84.3, dw=18.0, dh=13.5
//   BOLT_GRADES['A4-80']: Sy=600, Su=800
//   CLAMPED_MATERIALS['resin']: tau=65, bearing=30
//
//   Db  = (18.0 + 13.5) / 2 = 15.75
//   K   = 1.75/(2π×12) + 0.577×0.15×10.863/12 + 0.15×15.75/(2×12)
//       = 0.023209 + 0.078349 + 0.098438 ≈ 0.200
//   At  = 1.75/(2π) + 0.577×0.15×10.863 = 0.278465 + 0.940619 = 1.219084
//   dAs = √(4×84.3/π) = 10.359
//   Fy_denom = 1 + 3×(3/10.359 × 1.219084)² = 1 + 3×0.124627 = 1.373881
//   Fy  = 600×84.3 / √1.373881 / 1000 = 50580 / 1.172126 / 1000 = 43.15 kN
//   T_lim = 0.200 × 12 × 43.15 = 103.6 N·m
//   T_jis = 103.6 / 1.5 = 69.1 N·m
//
//   resin（軟質材）: bearing=30
//   bArea = π/4×(18²-13.5²) = π/4×141.75 = 111.37 mm²
//   FbA = 30×111.37/1000 = 3.341 kN（最小 → dominant='座面陥没'）
//   dominant.T = 3.341 × K×d = 3.341 × 2.40 = 8.018 N·m
//   T_mat = 8.018 / 1.5 = 5.345 N·m
//   T_rec = min(69.1, 5.345) = 5.345 → isMaterialLimit=true
console.log('\n【TC-05】 M12 / A4-80 / resin / dry（ステンレスボルト 最軟質材）');
{
  const r = Bolt.calc({ d: 12, grade: 'A4-80', partMat: 'resin', mu: 'dry' });
  checkNull('error = null', r.error);
  check('K ≈ 0.200', r.K, 0.200, 1e-3);
  check('Fy kN', r.Fy, 43.15, 0.20);
  check('T_lim N·m', r.T_lim, 103.6, 0.5);
  check('T_jis N·m', r.T_jis, 69.1, 0.5);
  checkTrue('isMaterialLimit = true（エンプラ軟質材）', r.isMaterialLimit);
  checkLt('T_rec < T_jis', r.T_rec, r.T_jis);
  check('T_rec ≈ 5.35 N·m（エンプラ面圧制限）', r.T_rec, 5.35, 0.20);
  checkEq('dominant = 座面陥没', r.dominant, '座面陥没');
  checkTrue('warnings.length > 0', r.warnings.length > 0);
}

// ─── TC-06: M20 / 10.9 / steel / dry（T_lim が大きい大径ボルト）──
// 手計算根拠:
//   BOLT_DATA[20]: p=2.5, d2=18.376, As=245, dw=30.0, dh=22.0
//   K = 2.5/(2π×20) + 0.577×0.15×18.376/20 + 0.15×26.0/(2×20)
//     = 0.019894 + 0.079547 + 0.097500 = 0.196941
//   Fy ≈ 940×245 / √1.342506 / 1000 ≈ 198.8 kN
//   T_lim ≈ 0.19694 × 20 × 198.8 ≈ 783 N·m（M10の約8倍）
console.log('\n【TC-06】 M20 / 10.9 / steel / dry（T_lim >> 200 N·m）');
{
  const r = Bolt.calc({ d: 20, grade: '10.9', partMat: 'steel', mu: 'dry' });
  checkNull('error = null', r.error);
  check('K ≈ 0.197', r.K, 0.19694, 1e-4);
  check('Fy ≈ 198.8 kN', r.Fy, 198.8, 1.0);
  checkGt('T_lim > 700 N·m', r.T_lim, 700);
  checkFalse('isMaterialLimit = false', r.isMaterialLimit);
  // M20/10.9 の T_lim は M10/10.9（94.31）の約8倍以上
  checkTrue('T_lim(M20) >> T_lim(M10) × 4', r.T_lim > 94.31 * 4);
}

// ─── TC-07: 摩擦条件比較（μ が小さいほど K・T_lim が低下）─────────
// 手計算根拠（M10 / 8.8 / steel）:
//   dry   (mt=mw=0.15): K=0.20324, Fy=32.58 kN, T_lim=66.24 N·m
//   lube  (mt=mw=0.10): K=0.14345, Fy=34.79 kN, T_lim=49.93 N·m
//   grease(mt=mw=0.08): K=0.11954, Fy=35.59 kN, T_lim=42.53 N·m
//   ※Fy は At が小さくなるほど大きくなる（複合応力 torsion の低減）
console.log('\n【TC-07】 摩擦条件比較 M10 / 8.8 / steel（dry → lube → grease）');
{
  const rdry   = Bolt.calc({ d: 10, grade: '8.8', partMat: 'steel', mu: 'dry'   });
  const rlube  = Bolt.calc({ d: 10, grade: '8.8', partMat: 'steel', mu: 'lube'  });
  const rgrease= Bolt.calc({ d: 10, grade: '8.8', partMat: 'steel', mu: 'grease'});

  // 手計算値照合
  check('K_dry',    rdry.K,    0.20324, 1e-4);
  check('K_lube',   rlube.K,   0.14345, 1e-4);
  check('K_grease', rgrease.K, 0.11954, 1e-4);

  check('T_lim_dry N·m',    rdry.T_lim,    66.24, 0.20);
  check('T_lim_lube N·m',   rlube.T_lim,   49.93, 0.20);
  check('T_lim_grease N·m', rgrease.T_lim, 42.53, 0.20);

  // 単調減少確認（K_dry > K_lube > K_grease）
  checkTrue('K_dry > K_lube', rdry.K > rlube.K);
  checkTrue('K_lube > K_grease', rlube.K > rgrease.K);

  // T_lim も単調減少
  checkTrue('T_lim_dry > T_lim_lube', rdry.T_lim > rlube.T_lim);
  checkTrue('T_lim_lube > T_lim_grease', rlube.T_lim > rgrease.T_lim);

  // Fy は μ が小さいほど大きくなる（複合応力 torsion 成分が減少）
  checkTrue('Fy_dry < Fy_lube < Fy_grease', rdry.Fy < rlube.Fy && rlube.Fy < rgrease.Fy);
}

// ─── TC-08: ねじ込み深さ dep が山せん断荷重 Fstr に影響 ──────────
// dep=1.0（デフォルト）と dep=2.0 の比較（M10 / 10.9 / steel / dry）
//   nTh(dep=1.0) = (1.0×10 - 0.5×1.5) / 1.5 = 6.167
//   nTh(dep=2.0) = (2.0×10 - 0.5×1.5) / 1.5 = 12.833
//   Fstr ∝ nTh → dep=2.0 で Fstr が約2倍に増加
//   K, Fy, T_lim は dep に依存しない
console.log('\n【TC-08】 ねじ込み深さ dep 比較（M10 / 10.9 / steel / dry）');
{
  const r1 = Bolt.calc({ d: 10, grade: '10.9', partMat: 'steel', mu: 'dry', dep: 1.0 });
  const r2 = Bolt.calc({ d: 10, grade: '10.9', partMat: 'steel', mu: 'dry', dep: 2.0 });

  // K, Fy, T_lim は dep に依存しない
  check('K: dep=1.0 vs dep=2.0 不変', r1.K, r2.K, 1e-9);
  check('Fy: dep=1.0 vs dep=2.0 不変', r1.Fy, r2.Fy, 1e-6);
  check('T_lim: dep=1.0 vs dep=2.0 不変', r1.T_lim, r2.T_lim, 1e-6);

  // 山せん断（Fstr）は dep が増えると大きくなる
  const fstr1 = r1.failModes.find(m => m.name === '山せん断');
  const fstr2 = r2.failModes.find(m => m.name === '山せん断');
  checkTrue('Fstr(dep=2.0) > Fstr(dep=1.0)', fstr2.F > fstr1.F);
  checkGt('Fstr(dep=2.0) / Fstr(dep=1.0) ≈ 2', fstr2.F / fstr1.F, 1.8);

  // dep=1.0: Fstr=33.53 kN
  check('Fstr(dep=1.0) ≈ 33.53 kN', fstr1.F, 33.53, 0.20);
  // dep=2.0: Fstr=69.78 kN（nTh が約2倍なので Fstr も約2倍）
  check('Fstr(dep=2.0) ≈ 69.78 kN', fstr2.F, 69.78, 0.50);
}

// ─── TC-11〜14: バリデーション ──────────────────────────────────
console.log('\n【TC-11〜14】 バリデーション（エラー検出）');
{
  // TC-11: 未登録ボルト径
  const r11 = Bolt.calc({ d: 7, grade: '8.8', partMat: 'steel', mu: 'dry' });
  checkError('TC-11: M7（未登録）→ エラー', r11);

  // TC-12: 未登録強度区分
  const r12 = Bolt.calc({ d: 10, grade: '7.8', partMat: 'steel', mu: 'dry' });
  checkError('TC-12: 強度区分 "7.8"（未登録）→ エラー', r12);

  // TC-13: 未登録被締結材
  const r13 = Bolt.calc({ d: 10, grade: '8.8', partMat: 'copper', mu: 'dry' });
  checkError('TC-13: 被締結材 "copper"（未登録）→ エラー', r13);

  // TC-14: 未登録摩擦条件
  const r14 = Bolt.calc({ d: 10, grade: '8.8', partMat: 'steel', mu: 'oil' });
  checkError('TC-14: 摩擦条件 "oil"（未登録）→ エラー', r14);
}

// ─── TC-15: T_range ±10% 整合性（全ケース） ─────────────────────
console.log('\n【TC-15】 T_range ±10% 整合性 確認（6ケース）');
{
  const cases = [
    { d: 10, grade: '10.9', partMat: 'steel', mu: 'dry' },
    { d: 8,  grade: '8.8',  partMat: 'aluminum', mu: 'lube' },
    { d: 6,  grade: '4.6',  partMat: 'sus304', mu: 'grease' },
    { d: 16, grade: '12.9', partMat: 's45c',  mu: 'dry' },
    { d: 12, grade: 'A4-80',partMat: 'resin', mu: 'dry' },
    { d: 20, grade: '10.9', partMat: 'steel', mu: 'dry' },
  ];
  cases.forEach(c => {
    const r = Bolt.calc(c);
    const label = `M${c.d}/${c.grade}/${c.partMat}/${c.mu}`;
    check(`${label}: T_range.min = T_rec×0.9`, r.T_range.min, r.T_rec * 0.9, 0.01);
    check(`${label}: T_range.max = T_rec×1.1`, r.T_range.max, r.T_rec * 1.1, 0.01);
  });
}

// ─── TC-01 追加照合：failModes 全数値（最重要ケース完全照合） ──────
// 参考: BoltSense アプリの表示値がこのケースを基準にしている
console.log('\n【TC-01 詳細】 failModes 全数値 完全照合（M10 / 10.9 / steel / dry）');
{
  const r = Bolt.calc({ d: 10, grade: '10.9', partMat: 'steel', mu: 'dry' });
  const modeMap = {};
  r.failModes.forEach(m => { modeMap[m.name] = m; });

  // 各破損モード トルク値 T = F × K×d
  const Knd = r.K * 10;
  check('座面陥没 T [N·m]', modeMap['座面陥没'].T, modeMap['座面陥没'].F * Knd, 0.01);
  check('山せん断 T [N·m]', modeMap['山せん断'].T, modeMap['山せん断'].F * Knd, 0.01);
  check('ボルト破断 T [N·m]', modeMap['ボルト破断'].T, modeMap['ボルト破断'].F * Knd, 0.01);

  // T_jis = T_lim / sf
  check('T_jis = T_lim / 1.5', r.T_jis, r.T_lim / 1.5, 1e-6);
  // T_rec = T_jis（鋼は軟質材外なので低減なし）
  check('T_rec = T_jis（鋼は制限なし）', r.T_rec, r.T_jis, 1e-6);
  // warnings は空
  checkTrue('warnings 空（鋼は警告なし）', r.warnings.length === 0);
}

// ─── Spring / Resonance / Bearing モジュール非破壊確認 ──────────
console.log('\n【非破壊確認】 既存モジュールへの影響なし');
{
  // Spring モジュールが正常動作
  const rs = MechSense.Spring.calc({ d: 2.0, D: 15, Na: 5, P: 50, mat: 'SW-B' });
  checkNull('Spring.calc エラーなし', rs.error);
  check('Spring: τ/σB ≈ 0.1945', rs.ratio, 0.1945, 0.001);
  checkEq('Spring: status = OK', rs.status, 'OK');

  // Resonance モジュールが正常動作
  const rr = MechSense.Resonance.calc({ d: 2.0, D: 15, Na: 5, mat: 'SW-B' });
  checkNull('Resonance.calc エラーなし', rr.error);
  checkGt('Resonance: fn_surge > 800 Hz', rr.fn_surge, 800);

  // Bearing モジュールが正常動作
  const rb = MechSense.Bearing.calc({ jis: '6205', rpm: 1797 });
  checkNull('Bearing.calc エラーなし', rb.error);
  check('Bearing: BPFO ≈ 107.0 Hz（CWRU基準値）', rb.bpfo, 107.0, 1.0);
}

// ─── 最終結果 ─────────────────────────────────────────────────
console.log('\n' + '='.repeat(60));
console.log(`結果: ${pass}/${pass + fail} PASS`);
if (fail === 0) {
  console.log('🎉 全テスト PASS — mechsense-core.js v1.4.0 Bolt モジュール 数値検証OK');
  console.log('   JIS B 1083 式(2)(7)(8) との照合完了');
  console.log('   BoltSense Google Play 申請に向けた計算品質の担保が完了');
} else {
  console.log(`⚠️  ${fail} 件 FAIL — 上記の ❌ を確認してください`);
}
console.log('='.repeat(60));

