/**
 * verify-bolt-jis.js
 * JIS B 1083 ボルト締付計算 数値検証テスト
 * mechsense-core.js v1.4.0 Bolt モジュール
 *
 * 検証方針:
 *   各テストケースで JIS B 1083 の計算式を手計算し、
 *   mechsense-core.js の計算結果と照合する。
 *
 * JIS B 1083 主要計算式:
 *   Db  = (dw + dh) / 2                                        (座面径)
 *   K   = p/(2πd) + 0.577×mt×d2/d + mw×Db/(2d)              (トルク係数 式(2))
 *   At  = p/(2π) + 0.577×mt×d2                               (応力項)
 *   dAs = √(4×As/π)                                           (有効断面相当径)
 *   Fy  = Sy×As / √(1 + 3×(3/dAs × At)²) / 1000             (降伏軸力 式(7), kN)
 *   T_lim = K×d×Fy                                            (限界トルク 式(8), N·m)
 *   T_jis = T_lim / sf                                         (JIS推奨 sf=1.5)
 *
 * 実行: node verify-bolt-jis.js
 */

'use strict';

const MechSense = require('./mechsense-core.js');
const Bolt = MechSense.Bolt;

let pass = 0, fail = 0;

// ─── ヘルパー ────────────────────────────────────────

function check(label, actual, expected, tol = 0.01) {
  const ok = Math.abs(actual - expected) <= tol;
  const icon = ok ? '✅' : '❌';
  if (ok) pass++; else fail++;
  if (!ok) {
    console.log(`  ${icon} ${label}: 期待=${expected.toFixed(5)}, 実際=${actual.toFixed(5)}, 差=${(actual - expected).toFixed(6)}`);
  } else {
    console.log(`  ${icon} ${label}: ${actual.toFixed(4)} (期待 ${expected.toFixed(4)})`);
  }
}

function checkEq(label, actual, expected) {
  const ok = actual === expected;
  const icon = ok ? '✅' : '❌';
  if (ok) pass++; else fail++;
  console.log(`  ${icon} ${label}: ${JSON.stringify(actual)} (期待 ${JSON.stringify(expected)})`);
}

function checkTrue(label, actual) {
  const ok = actual === true;
  if (ok) pass++; else fail++;
  console.log(`  ${ok ? '✅' : '❌'} ${label}: ${actual}`);
}

function checkFalse(label, actual) {
  const ok = actual === false;
  if (ok) pass++; else fail++;
  console.log(`  ${ok ? '✅' : '❌'} ${label}: ${actual}`);
}

function checkNull(label, actual) {
  const ok = actual === null;
  if (ok) pass++; else fail++;
  console.log(`  ${ok ? '✅' : '❌'} ${label}: ${actual}`);
}

function checkGt(label, actual, threshold) {
  const ok = actual > threshold;
  if (ok) pass++; else fail++;
  console.log(`  ${ok ? '✅' : '❌'} ${label}: ${actual.toFixed(3)} (> ${threshold})`);
}

function checkLt(label, actual, threshold) {
  const ok = actual < threshold;
  if (ok) pass++; else fail++;
  console.log(`  ${ok ? '✅' : '❌'} ${label}: ${actual.toFixed(3)} (< ${threshold})`);
}

function checkNoError(r) {
  const ok = r.error === null;
  if (ok) pass++; else fail++;
  if (!ok) console.log(`  ❌ エラーあり: ${r.error}`);
}

function checkError(label, r) {
  const ok = typeof r.error === 'string' && r.error.length > 0;
  if (ok) pass++; else fail++;
  console.log(`  ${ok ? '✅' : '❌'} ${label}: error="${r.error}"`);
}

// ─── モジュール構造テスト ───────────────────────────────

console.log('\n【モジュール構造確認】');
checkEq('MechSense.Bolt 存在', typeof Bolt, 'object');
checkEq('Bolt.calc 関数', typeof Bolt.calc, 'function');
checkEq('Bolt.BOLTS 存在', typeof Bolt.BOLTS, 'object');
checkEq('Bolt.GRADES 存在', typeof Bolt.GRADES, 'object');
checkEq('Bolt.CLAMPED_MATERIALS 存在', typeof Bolt.CLAMPED_MATERIALS, 'object');
checkEq('Bolt.FRICTION 存在', typeof Bolt.FRICTION, 'object');

// ─── TC-09: BOLT_DATA 構造確認 ─────────────────────────
console.log('\n【TC-09】 BOLT_DATA 構造確認（JIS B 1083 附属書 17サイズ M3〜M42）');
{
  // JIS B 1083 対応サイズ: M3,4,5,6,8,10,12,16,20,22,24,27,30,33,36,39,42
  const EXPECTED_SIZES = [3, 4, 5, 6, 8, 10, 12, 16, 20, 22, 24, 27, 30, 33, 36, 39, 42];
  const keys = Object.keys(Bolt.BOLTS).map(Number);
  checkEq('サイズ数 = 17', keys.length, 17);

  EXPECTED_SIZES.forEach(d => {
    const b = Bolt.BOLTS[d];
    checkTrue(`M${d} 存在`, !!b);
    if (b) {
      checkTrue(`M${d}: p > 0`, b.p > 0);
      checkTrue(`M${d}: d2 < d`, b.d2 < d);
      checkTrue(`M${d}: As > 0`, b.As > 0);
      checkTrue(`M${d}: dw > d`, b.dw > d);
    }
  });

  // M10 特定値確認（JIS B 1083 附属書）
  const b10 = Bolt.BOLTS[10];
  check('M10: p = 1.5 mm', b10.p, 1.5, 1e-9);
  check('M10: d2 = 9.026 mm', b10.d2, 9.026, 1e-3);
  check('M10: As = 58.0 mm²', b10.As, 58.0, 1e-9);
  check('M10: dw = 16.0 mm', b10.dw, 16.0, 1e-9);
  check('M10: dh = 11.0 mm', b10.dh, 11.0, 1e-9);
}

// ─── TC-10: BOLT_GRADES 確認 ───────────────────────────
console.log('\n【TC-10】 BOLT_GRADES 確認（12区分 JIS B 1051 / ISO 898-1）');
{
  const expectedGrades = ['4.6', '4.8', '8.8', '10.9', '12.9', 'A2-70', 'A4-70', 'A4-80', 'A2017', 'A5052', 'A6061', 'C3604'];
  checkEq('強度区分数 = 12', Object.keys(Bolt.GRADES).length, 12);
  expectedGrades.forEach(g => {
    checkTrue(`区分 "${g}" 存在`, !!Bolt.GRADES[g]);
  });
  // 強度値確認
  check('10.9: Sy = 940 MPa', Bolt.GRADES['10.9'].Sy, 940, 1e-9);
  check('12.9: Sy = 1100 MPa', Bolt.GRADES['12.9'].Sy, 1100, 1e-9);
  check('8.8: Sy = 660 MPa', Bolt.GRADES['8.8'].Sy, 660, 1e-9);
  check('4.6: Sy = 240 MPa', Bolt.GRADES['4.6'].Sy, 240, 1e-9);
  // 単調増加確認（強度区分が上がるほど Sy が高い）
