//       = 0.023873 + 0.078120 + 0.101250 = 0.20324
//   At  = 1.5/(2π) + 0.577×0.15×9.026 = 0.238732 + 0.781198 = 1.01993
//   dAs = √(4×58.0/π) = √73.847 = 8.5939
//   Fy_denom = 1 + 3×(3/8.5939 × 1.01993)² = 1 + 3×0.126777 = 1.38033
//   Fy  = 940×58.0 / √1.38033 / 1000 = 54520 / 1.17488 / 1000 = 46.40 kN
//   T_lim = 0.20324 × 10 × 46.40 = 94.31 N·m
//   T_jis = 94.31 / 1.5 = 62.88 N·m
//
//   破損モード（CLAMPED_MATERIALS['steel']: tau=400, bearing=220）:
//   bArea = π/4×(16²-11²) = π/4×135 = 105.97 mm²
//   nTh = (1.0×10 - 0.5×1.5) / 1.5 = 6.167
//   Fbrk = 1040×58.0/1000 = 60.32 kN
//   Fstr = 400×π×10×0.75×6.167×0.577/1000 = 33.53 kN
