//   lube  (mt=mw=0.10): K=0.14345, Fy=34.79 kN, T_lim=49.93 N·m
//   grease(mt=mw=0.08): K=0.11954, Fy=35.59 kN, T_lim=42.53 N·m
//   ※Fy は At が小さくなるほど大きくなる（複合応力 torsion の低減）
console.log('\n【TC-07】 摩擦条件比較 M10 / 8.8 / steel（dry → lube → grease）');
{
  const rdry   = Bolt.calc({ d: 10, grade: '8.8', partMat: 'steel', mu: 'dry'   });
  const rlube  = Bolt.calc({ d: 10, grade: '8.8', partMat: 'steel', mu: 'lube'  });
