  // 手計算値照合
  check('K_dry',    rdry.K,    0.20324, 1e-4);
  check('K_lube',   rlube.K,   0.14345, 1e-4);
  check('K_grease', rgrease.K, 0.11954, 1e-4);

  check('T_lim_dry N·m',    rdry.T_lim,    66.24, 0.20);
  check('T_lim_lube N·m',   rlube.T_lim,   49.93, 0.20);
  check('T_lim_grease N·m', rgrease.T_lim, 42.53, 0.20);

  // 単調減少確認（K_dry > K_lube > K_grease）
  checkTrue('K_dry > K_lube', rdry.K > rlube.K);
  checkTrue('K_lube > K_grease', rlube.K > rgrease.K);

  // T_lim も単調減少
  checkTrue('T_lim_dry > T_lim_lube', rdry.T_lim > rlube.T_lim);
  checkTrue('T_lim_lube > T_lim_grease', rlube.T_lim > rgrease.T_lim);

  // Fy は μ が小さいほど大きくなる（複合応力 torsion 成分が減少）
  checkTrue('Fy_dry < Fy_lube < Fy_grease', rdry.Fy < rlube.Fy && rlube.Fy < rgrease.Fy);
