// ─── TC-08: ねじ込み深さ dep が山せん断荷重 Fstr に影響 ──────────
// dep=1.0（デフォルト）と dep=2.0 の比較（M10 / 10.9 / steel / dry）
//   nTh(dep=1.0) = (1.0×10 - 0.5×1.5) / 1.5 = 6.167
//   nTh(dep=2.0) = (2.0×10 - 0.5×1.5) / 1.5 = 12.833
//   Fstr ∝ nTh → dep=2.0 で Fstr が約2倍に増加
//   K, Fy, T_lim は dep に依存しない
console.log('\n【TC-08】 ねじ込み深さ dep 比較（M10 / 10.9 / steel / dry）');
{
  const r1 = Bolt.calc({ d: 10, grade: '10.9', partMat: 'steel', mu: 'dry', dep: 1.0 });
  const r2 = Bolt.calc({ d: 10, grade: '10.9', partMat: 'steel', mu: 'dry', dep: 2.0 });

  // K, Fy, T_lim は dep に依存しない
  check('K: dep=1.0 vs dep=2.0 不変', r1.K, r2.K, 1e-9);
  check('Fy: dep=1.0 vs dep=2.0 不変', r1.Fy, r2.Fy, 1e-6);
  check('T_lim: dep=1.0 vs dep=2.0 不変', r1.T_lim, r2.T_lim, 1e-6);

  // 山せん断（Fstr）は dep が増えると大きくなる
  const fstr1 = r1.failModes.find(m => m.name === '山せん断');
  const fstr2 = r2.failModes.find(m => m.name === '山せん断');
  checkTrue('Fstr(dep=2.0) > Fstr(dep=1.0)', fstr2.F > fstr1.F);
  checkGt('Fstr(dep=2.0) / Fstr(dep=1.0) ≈ 2', fstr2.F / fstr1.F, 1.8);

  // dep=1.0: Fstr=33.53 kN
  check('Fstr(dep=1.0) ≈ 33.53 kN', fstr1.F, 33.53, 0.20);
  // dep=2.0: Fstr=69.78 kN（nTh が約2倍なので Fstr も約2倍）
  check('Fstr(dep=2.0) ≈ 69.78 kN', fstr2.F, 69.78, 0.50);
}

